import React from 'react';

const Reports: React.FC = () => {
  return (
    <div className="space-y-6">
      <h2 className="text-2xl font-bold tracking-tight">Security Reports</h2>
      <p className="text-gray-500">Generate and export compliance and security incident reports.</p>

      <div className="rounded-md border bg-card p-8 text-center text-gray-500">
        You have no generated reports for the current period. 
        <br />
        <button className="mt-4 px-4 py-2 border rounded hover:bg-gray-50 dark:hover:bg-slate-800">
          Generate Weekly Summary
        </button>
      </div>
    </div>
  );
};

export default Reports;
